1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const ITEM_BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_PREMIUM = 60;
16	
17	type Item = { type: string };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Step = QuoteStep;
20	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
21	
22	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
23	
24	const groupedBasePremium = (type: string, count: number): number => {
25	  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
26	    return COMPONENT_BLOCK_PREMIUM;
27	  }
28	  return count * ITEM_BASE_PREMIUM[type];
29	};
30	
31	const countByType = (items: Item[]): Map<string, number> => {
32	  const counts = new Map<string, number>();
33	  for (const item of items) {
34	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
35	  }
36	  return counts;
37	};
38	
39	const sumBasePremiums = (items: Item[]): number =>
40	  Array.from(countByType(items)).reduce(
41	    (total, [type, count]) => total + groupedBasePremium(type, count),
42	    0,
43	  );
44	
45	const quotePremium = (items: Item[]): number => {
46	  const basePremium = sumBasePremiums(items);
47	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
48	  const insurancePremium = Math.ceil(basePremium + firstInsuranceSurcharge);
49	  return insurancePremium + PROCESSING_FEE;
50	};
51	
52	const runStep = (step: Step) => ({ premium: quotePremium(step.items) });
53	
54	export const runScenario = (scenario: Scenario): unknown => ({
55	  results: scenario.steps.map(runStep),
56	});
57

